export const deriveCombatStats = (
  state: GameState,
  actorId: CombatActorId,
): CombatStats | null => {
  const actor = combatActor(state, actorId);

  if (actor === null) {
    return null;
  }

  const stats =
    actor.kind === "player"
      ? playerBaseStats(state)
      : {
          attack: actor.entity.definition.stats.attack,
          defense: actor.entity.definition.stats.defense,
        };

  const withStatusModifiers = applyStatusModifiers(stats, actor.statuses);

  return {
    attack: Math.max(
      config.combatMath.minimumDamage,
      withStatusModifiers.attack,
    ),
    defense: withStatusModifiers.defense,
  };
};

export const calculateBaseDamage = (
  attackerAttack: number,
  defenderDefense: number,
): number =>
  Math.max(
    config.combatMath.minimumDamage,
    attackerAttack - defenderDefense,
  );

export const calculateDamage = (
  attackerAttack: number,
  defenderDefense: number,
  varianceMultiplier: number,
): number =>
  Math.max(
    config.combatMath.minimumDamage,
    Math.round(
      calculateBaseDamage(attackerAttack, defenderDefense) *
        varianceMultiplier,
    ),
  );

export const resolveAttack = (
  state: GameState,
  attackerId: CombatActorId,
  defenderId: CombatActorId,
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);
  const defender = combatActor(state, defenderId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  if (defender === null) {
    return {
      illegal: true,
      reason: `defender ${defenderId} is not a combat actor`,
    };
  }

  if (!isAdjacent(attacker.position, defender.position)) {
    return {
      illegal: true,
      reason: `defender ${defenderId} is not adjacent to attacker ${attackerId}`,
    };
  }

  return resolveAttackRoll(state, attacker, defender);
};

export type BoltAttackOptions = {
  readonly range?: number;
};

export const resolveBoltAttack = (
  state: GameState,
  attackerId: CombatActorId,
  targetCell: Position,
  options: BoltAttackOptions = {},
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  const grid = gridFromState(state);
  if (grid === null) {
    return {
      illegal: true,
      reason: "floor geometry is not loaded",
    };
  }

  if (!inBounds(grid, targetCell)) {
    return {
      illegal: true,
      reason: `bolt target cell (${targetCell.x}, ${targetCell.y}) is outside the map`,
    };
  }

  const range =
    options.range ?? bounds.effectVocabulary.targetingShapes.boltRangeTiles.max;
  const rangeBounds = bounds.effectVocabulary.targetingShapes.boltRangeTiles;

  if (
    !Number.isSafeInteger(range) ||
    range < rangeBounds.min ||
    range > rangeBounds.max
  ) {
    return {
      illegal: true,
      reason: `bolt range must be ${rangeBounds.min}-${rangeBounds.max}`,
    };
  }

  const target = findBoltTarget(state, grid, attacker, targetCell, range);

  if (target.status === "miss") {
    return {
      state,
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: null,
          attackerAttack: null,
          defenderDefense: null,
          hitRoll: null,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: target.reason,
        }),
      ],
    };
  }

  return resolveAttackRoll(state, attacker, target.actor);
};

export const resolveAttackAction: ActionResolver<AttackAction> = (
  state,
  action,
): ActionResolverResult => resolveAttack(state, "player", action.targetId);

export const registerCombatActionResolver = (): (() => void) =>
  registerActionResolver("attack", resolveAttackAction);

export const unregisterCombatActionResolver = registerCombatActionResolver();

export const registerLootDropHook = (hook: LootDropHook): (() => void) => {
  const previous = lootDropHook;
  lootDropHook = hook;

  lootDropHook = hook;

  return () => {
    if (lootDropHook === hook) {
      lootDropHook = previous;
    }
  };
};

const resolveAttackRoll = (
  state: GameState,
  attacker: CombatActor,
  defender: CombatActor,
): ActionResolverResult => {
  const attackerStats = deriveCombatStats(state, attacker.id);
  const defenderStats = deriveCombatStats(state, defender.id);

  if (attackerStats === null || defenderStats === null) {
    return {
      illegal: true,
      reason: "combat stats could not be derived",
    };
  }

  const rngContext = combatRngContextFor(state);
  const hitRoll = rollInt(rngContext, HIT_ROLL_MIN, HIT_ROLL_MAX);

  if (hitRoll > config.combatMath.hitChancePercent) {
    return {
      state: withCombatRngCursor(state, rngContext),
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: defender.id,
          attackerAttack: attackerStats.attack,
          defenderDefense: defenderStats.defense,
          hitRoll,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: "hit_roll",
        }),
      ],
    };
  }

  const varianceMultiplier = rollVarianceMultiplier(rngContext);
  const baseDamage = calculateBaseDamage(
    attackerStats.attack,
    defenderStats.defense,
  );
  const damage = Math.max(
    config.combatMath.minimumDamage,
    Math.round(baseDamage * varianceMultiplier),
  );
  const defenderHpAfter = Math.max(0, defender.hp - damage);
  const damagedState = withActorHp(
    withCombatRngCursor(state, rngContext),
    defender,
    defenderHpAfter,
  );
  const events: TurnEvent[] = [
    combatEvent(state, "attack_hit", {
      actorId: attacker.id,
      defenderId: defender.id,
      attackerAttack: attackerStats.attack,
      defenderDefense: defenderStats.defense,
      baseDamage,
      damage,
      hitRoll,
      hitChancePercent: config.combatMath.hitChancePercent,
      varianceMultiplier,
      defenderHpBefore: defender.hp,
      defenderHpAfter,
    }),
  ];

  if (defenderHpAfter > 0) {
    return {
      state: damagedState,
      events,
    };
  }

  const deathResult = applyDeath(damagedState, defender.id, {
    attribution: {
      kind: "killer",
      killerId: attacker.id,
    },
  });

  return {
    state: deathResult.state,
    events: [...events, ...deathResult.events],
  };
};

const playerBaseStats = (state: GameState): CombatStats => {
  const attackGrowth = config.playerCharacter.stats.baseAttack;
  const defenseGrowth = config.playerCharacter.stats.baseDefense;
  const levelOffset = Math.max(
    0,
    state.player.level - config.playerCharacter.stats.level.start,
  );
  const weaponBonus =
    state.player.equipment.weapon?.definition.weapon?.attackBonus ?? 0;
  const armorBonus =
    state.player.equipment.armor?.definition.armor?.defenseBonus ?? 0;
  const charmModifiers = equipmentBuffModifiers(state.player.equipment.charms);

  return {
    attack:
      attackGrowth.start +
      Math.floor(levelOffset / attackGrowth.growthEveryLevels) *
        attackGrowth.growthAmount +
      weaponBonus +
      charmModifiers.attack,
    defense:
      defenseGrowth.start +
      Math.floor(levelOffset / defenseGrowth.growthEveryLevels) *
        defenseGrowth.growthAmount +
      armorBonus +
      charmModifiers.defense,
  };
};

const equipmentBuffModifiers = (
  charms: readonly (PlayerItemStack | null)[],
): CombatStats => {
  let attack = 0;
  let defense = 0;

  for (const charm of charms) {
    const effects = charm?.definition.charm?.passive.effects ?? [];

    for (const effect of effects) {
      const modifier = buffModifierFromEffect(effect);

      if (modifier?.stat === "ATK") {
        attack += modifier.magnitude;
      }

      if (modifier?.stat === "DEF") {
        defense += modifier.magnitude;
      }
    }
  }

  return { attack, defense };
};

const applyStatusModifiers = (
  stats: CombatStats,
  statuses: readonly StatusApplication[],
): CombatStats => {
  let attack = stats.attack;
  let defense = stats.defense;

  for (const status of statuses) {
    if (status.status === "shield") {
      defense += config.statusMagnitudes.shieldDefBonus;
    }

    if (status.status === "weaken") {
      attack += config.statusMagnitudes.weakenAtkPenalty;
    }

    const modifier = buffModifierFromRuntimeStatus(status);
    if (modifier?.stat === "ATK") {
      attack += modifier.magnitude;
    }

    if (modifier?.stat === "DEF") {
      defense += modifier.magnitude;
    }
  }

  return { attack, defense };
};

const buffModifierFromEffect = (
  effect: Effect,
): { readonly stat: "ATK" | "DEF"; readonly magnitude: number } | null => {
  if (effect.kind !== "buff_stat" || effect.buffStat === null) {
    return null;
  }

  return {
    stat: effect.buffStat.stat,
    magnitude: effect.buffStat.magnitude,
  };
};

const buffModifierFromRuntimeStatus = (
  status: StatusApplication,
): { readonly stat: "ATK" | "DEF"; readonly magnitude: number } | null => {
  const runtime = status as unknown as {
    readonly kind?: unknown;
    readonly stat?: unknown;
    readonly magnitude?: unknown;
    readonly buffStat?: {
      readonly stat?: unknown;
      readonly magnitude?: unknown;
    };
  };

  if (
    runtime.kind === "buff_stat" &&
    isCombatStat(runtime.stat) &&
    isSafeIntegerNumber(runtime.magnitude)
  ) {
    return {
      stat: runtime.stat,
      magnitude: runtime.magnitude,
    };
  }

  if (
    runtime.buffStat !== undefined &&
    isCombatStat(runtime.buffStat.stat) &&
    isSafeIntegerNumber(runtime.buffStat.magnitude)
  ) {
    return {
      stat: runtime.buffStat.stat,
      magnitude: runtime.buffStat.magnitude,
    };
  }

  return null;
};

const isCombatStat = (value: unknown): value is "ATK" | "DEF" =>
  value === "ATK" || value === "DEF";

const isSafeIntegerNumber = (value: unknown): value is number =>
  typeof value === "number" && Number.isSafeInteger(value);

const combatRngContextFor = (state: GameState): MutableRngContext => {
  const previousDraws = state.rng.streams[COMBAT_RNG_STREAM_ID]?.draws ?? 0;
  const rng = createRng(state.rng.rootSeed);
  const combatRng = rng.fork("combat");

  for (let index = 0; index < previousDraws; index += 1) {
    combatRng.nextUint32();
  }

  return {
    rng: combatRng,
    initialDraws: previousDraws,
    drawsUsed: 0,
  };
};

const withCombatRngCursor = (
  state: GameState,
  context: MutableRngContext,
): GameState => {
  const existing = state.rng.streams[COMBAT_RNG_STREAM_ID];

  return {
    ...state,
    rng: {
      ...state.rng,
      streams: {
        ...state.rng.streams,
        [COMBAT_RNG_STREAM_ID]: {
          streamId: COMBAT_RNG_STREAM_ID,
          seed: existing?.seed ?? state.rng.rootSeed,
          parentStreamId: existing?.parentStreamId ?? ROOT_RNG_STREAM_ID,
          draws: context.initialDraws + context.drawsUsed,
        },
      },
    },
  };
};

const rollInt = (
  context: MutableRngContext,
  min: number,
  max: number,
): number => {
  const range = max - min + 1;
  const limit = UINT32_SIZE - (UINT32_SIZE % range);
  let value = drawUint32(context);

  while (value >= limit) {
    value = drawUint32(context);
  }

  return min + (value % range);
};

const rollVarianceMultiplier = (context: MutableRngContext): number => {
  const unit = drawUint32(context) / UINT32_SIZE;
  const variance = config.combatMath.varianceMultiplier;

  return variance.min + unit * (variance.max - variance.min);
};

const drawUint32 = (context: MutableRngContext): number => {
  context.drawsUsed += 1;

  return context.rng.nextUint32();
};

const findBoltTarget = (
  state: GameState,
  grid: TileGrid,
  attacker: CombatActor,
  targetCell: Position,
  range: number,
): BoltTargetResult => {
  const cells = line(attacker.position, targetCell).slice(1, range + 1);
  let blocked = false;

  for (const cell of cells) {
    if (!inBounds(grid, cell)) {
      break;
    }

    const tile = getTile(grid, cell);
    if (!isTransparentTile(tile)) {
      blocked = true;
      break;
    }

    const target = damageableActorAt(state, cell, attacker.id);
    if (target !== null) {
      return canSee(grid, attacker.position, target.position, { radius: range })
        ? { status: "target", actor: target }
        : { status: "miss", reason: "line_of_sight_blocked" };
    }
  }

  return {
    status: "miss",
    reason: blocked ? "line_of_sight_blocked" : "no_target",
  };
};

const damageableActorAt = (
  state: GameState,
  position: Position,
  excludedActorId: CombatActorId,
): CombatActor | null => {
  if (
    excludedActorId !== "player" &&
    samePosition(state.player.position, position)
  ) {
    return combatActor(state, "player");
  }

  for (const entity of Object.values(state.entities).sort((a, b) =>
    a.id.localeCompare(b.id),
  )) {
    if (
      entity.id !== excludedActorId &&
      entity.kind === "enemy" &&
      samePosition(entity.position, position)
    ) {
      return combatActor(state, entity.id);
    }
  }

  return null;
};

export const applyDeath = (
  state: GameState,
  entityId: CombatActorId,
  options: ApplyDeathOptions,
): { readonly state: GameState; readonly events: readonly TurnEvent[] } => {
  const victim = combatActor(state, entityId);

  if (victim === null) {
    return { state, events: [] };
  }

  const events: TurnEvent[] = [
    combatEvent(state, "entity_died", {
      entityId: victim.id,
      kind: victim.kind,
      position: victim.position,
      xpYield: victim.kind === "enemy" ? victim.entity.definition.stats.xpYield : 0,
    }),
  ];

  if (victim.kind === "player") {
    return {
      state: {
        ...state,
        player: {
          ...state.player,
          hp: {
            ...state.player.hp,
            current: 0,
          },
        },
        run: {
          ...state.run,
          terminalStatus: config.runStructure.terminalStates.loss,
        },
      },
      events,
    };
  }

  let nextState = withoutEntity(state, victim.id);

  if (
    options.attribution.kind === "killer" &&
    options.attribution.killerId === "player"
  ) {
    const xpYield = victim.entity.definition.stats.xpYield;
    const totalXp = nextState.player.xp + xpYield;
    nextState = {
      ...nextState,
      player: {
        ...nextState.player,
        xp: totalXp,
      },
    };
    events.push(
      combatEvent(state, "xp_gained", {
        actorId: "player",
        sourceEntityId: victim.id,
        amount: xpYield,
        totalXp,
      }),
    );
  }

  const killerId =
    options.attribution.kind === "killer" ? options.attribution.killerId : null;
  const lootResult = normalizeLootDropResult(
    lootDropHook({
      state: nextState,
      victim: victim.entity,
      attribution: options.attribution,
      killerId,
    }),
  );

import { bounds, config } from "../../config/index.js";
import {
  StatusApplicationSchema,
  type StatusApplication,
  type StatusId,
} from "../../schemas/vocab/index.js";
import type { Rng } from "../rng/index.js";
import type {
  EngineLogEventDataByType,
  EnemyEntityInstance,
  EntityId,
  GameState,
} from "../state/index.js";
import {
  MOVE_DIRECTIONS,
  registerTickHook,
  type MoveDirection,
  type TickHook,
  type TickHooks,
  type TurnEvent,
} from "../turn/index.js";
import { applyDeath } from "./combat.js";

export type StatusEntityId = EntityId | "player";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly status_applied: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
      readonly duration: number;
    };
    readonly status_refreshed: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
      readonly duration: number;
    };
    readonly status_expired: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
    };
    readonly status_dropped_oldest: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
    };
    readonly status_tick: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
      readonly hpDelta: number;
    };
  }
}

type StatusLogEventType =
  | "status_applied"
  | "status_refreshed"
  | "status_expired"
  | "status_dropped_oldest"
  | "status_tick";

type StatusTickHookName = "damageOverTime" | "durations";

const MAX_CONCURRENT_STATUSES = bounds.statusVocabulary.maxConcurrentPerActor;

const HASTE_SLOW_PAIR: ReadonlySet<StatusId> = new Set(["haste", "slow"]);

const DOT_STATUSES: ReadonlySet<StatusId> = new Set(["poison", "burn", "regen"]);

export type ApplyStatusResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export const applyStatus = (
  state: GameState,
  entityId: StatusEntityId,
  status: StatusId,
  duration: number,
): ApplyStatusResult => {
  const parsed = StatusApplicationSchema.safeParse({ status, duration });
  if (!parsed.success) {
    return { state, events: [] };
  }

  const application = parsed.data;
  const events: TurnEvent[] = [];
  let statuses = statusesForEntity(state, entityId);

  if (HASTE_SLOW_PAIR.has(status)) {
    const opposite = status === "haste" ? "slow" : "haste";
    const hadOpposite = statuses.some((entry) => entry.status === opposite);
    if (hadOpposite) {
      statuses = statuses.filter((entry) => entry.status !== opposite);
    }
  }

  const existingIndex = statuses.findIndex(
    (entry) => entry.status === application.status,
  );

  if (existingIndex >= 0) {
    statuses = statuses.map((entry, index) =>
      index === existingIndex
        ? { status: application.status, duration: application.duration }
        : entry,
    );
    events.push(
      statusEvent(state, "status_refreshed", {
        entityId,
        status: application.status,
        duration: application.duration,
      }),
    );
  } else {
    if (statuses.length >= MAX_CONCURRENT_STATUSES) {
      const dropped = statuses[0];
      if (dropped !== undefined) {
        statuses = statuses.slice(1);
        events.push(
          statusEvent(state, "status_dropped_oldest", {
            entityId,
            status: dropped.status,
          }),
        );
      }
    }

    statuses = [...statuses, application];
    events.push(
      statusEvent(state, "status_applied", {
        entityId,
        status: application.status,
        duration: application.duration,
      }),
    );
  }

  return {
    state: withEntityStatuses(state, entityId, statuses),
    events,
  };
};

export const isStunned = (statuses: readonly StatusApplication[]): boolean =>
  statuses.some((entry) => entry.status === "stun" && entry.duration > 0);

export const slowActsThisTurn = (turn: number): boolean => turn % 2 === 0;

export const hasteExtraAction = (turn: number): boolean => turn % 2 === 1;

export const confusionRedirect = (
  rng: Rng,
  intendedDir: MoveDirection,
): MoveDirection => {
  void intendedDir;
  return rng.fork("status").pick(MOVE_DIRECTIONS.map((entry) => entry.direction));
};

export const blindFovRadius = (
  statuses: readonly StatusApplication[],
): number | null =>
  statuses.some((entry) => entry.status === "blind" && entry.duration > 0) ? 1 : null;

const tickDamageOverTime: TickHook = ({ state }) => {
  const events: TurnEvent[] = [];
  let nextState = state;

  for (const entityId of statusEntityIdsInOrder(nextState)) {
    const result = applyDotForEntity(nextState, entityId);
    nextState = result.state;
    events.push(...result.events);
  }

  return { state: nextState, events };
};

const tickDurations: TickHook = ({ state }) => {
  const events: TurnEvent[] = [];
  let nextState = state;

  for (const entityId of statusEntityIdsInOrder(nextState)) {
    const result = decrementDurationsForEntity(nextState, entityId);
    nextState = result.state;
    events.push(...result.events);
  }

  return { state: nextState, events };
};

export const statusTickHooks = {
  damageOverTime: tickDamageOverTime,
  durations: tickDurations,
} as const satisfies Pick<TickHooks, StatusTickHookName>;

export const unregisterStatusTickHooks = (() => {
  const unregisterDamageOverTime = registerTickHook(
    "damageOverTime",
    tickDamageOverTime,
  );
  const unregisterDurations = registerTickHook("durations", tickDurations);

  return () => {
    unregisterDurations();
    unregisterDamageOverTime();
  };
})();

const applyDotForEntity = (
  state: GameState,
  entityId: StatusEntityId,
): ApplyStatusResult => {
  const statuses = statusesForEntity(state, entityId);
  const dotStatuses = statuses.filter((entry) => DOT_STATUSES.has(entry.status));

  if (dotStatuses.length === 0) {
    return { state, events: [] };
  }

  const events: TurnEvent[] = [];
  let nextState = state;

  for (const entry of dotStatuses) {
    const hp = currentHp(nextState, entityId);
    if (hp === null) {
      continue;
    }

    let nextHp = hp.current;
    let hpDelta = 0;

    switch (entry.status) {
      case "poison":
        nextHp = Math.max(
          1,
          hp.current + config.statusMagnitudes.poisonHpPerTurn,
        );
        hpDelta = nextHp - hp.current;
        break;
      case "burn":
        nextHp = hp.current + config.statusMagnitudes.burnHpPerTurn;
        hpDelta = nextHp - hp.current;
        break;
      case "regen":
        nextHp = Math.min(
          hp.max,
          hp.current + config.statusMagnitudes.regenHpPerTurn,
        );
        hpDelta = nextHp - hp.current;
        break;
      default:
        continue;
    }

    if (hpDelta !== 0) {
      events.push(
        statusEvent(state, "status_tick", {
          entityId,
          status: entry.status,
          hpDelta,
        }),
      );
    }

    if (entry.status === "burn" && nextHp <= 0) {
      const death = applyBurnDeath(nextState, entityId);
      return {
        state: death.state,
        events: [...events, ...death.events],
      };
    }

    nextState = setEntityHp(nextState, entityId, nextHp);
  }

  return { state: nextState, events };
};

const decrementDurationsForEntity = (
  state: GameState,
  entityId: StatusEntityId,
): ApplyStatusResult => {
  const statuses = statusesForEntity(state, entityId);
  if (statuses.length === 0) {
    return { state, events: [] };
  }

  const events: TurnEvent[] = [];
  const remaining: StatusApplication[] = [];

  for (const entry of statuses) {
    const nextDuration = entry.duration - 1;
    if (nextDuration <= 0) {
      events.push(
        statusEvent(state, "status_expired", {
          entityId,
          status: entry.status,
        }),
      );
      continue;
    }

    remaining.push({
      status: entry.status,
      duration: nextDuration,
    });
  }

  return {
    state: withEntityStatuses(state, entityId, remaining),
    events,
  };
};

const statusEntityIdsInOrder = (state: GameState): readonly StatusEntityId[] => [
  "player",
  ...Object.keys(state.entities)
    .sort((a, b) => a.localeCompare(b))
    .map((id) => id as EntityId),
];

const statusesForEntity = (
  state: GameState,
  entityId: StatusEntityId,
): readonly StatusApplication[] => {
  if (entityId === "player") {
    return state.player.statuses;
  }

  return state.entities[entityId]?.statuses ?? [];
};

const withEntityStatuses = (
  state: GameState,
  entityId: StatusEntityId,
  statuses: readonly StatusApplication[],
): GameState => {
  if (entityId === "player") {
    return {
      ...state,
      player: {
        ...state.player,
        statuses,
      },
    };
  }

  const entity = state.entities[entityId];
  if (entity === undefined) {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [entityId]: {
        ...entity,
        statuses,
      },
    },
  };
};

const currentHp = (
  state: GameState,
  entityId: StatusEntityId,
): { readonly current: number; readonly max: number } | null => {
  if (entityId === "player") {
    return state.player.hp;
  }

  const entity = state.entities[entityId];
  if (entity === undefined || entity.currentHP === null) {
    return null;
  }

  if (entity.kind === "enemy") {
    return {
      current: entity.currentHP,
      max: entity.definition.stats.hp,
    };
  }

  return null;
};

const setEntityHp = (
  state: GameState,
  entityId: StatusEntityId,
  current: number,
): GameState => {
  if (entityId === "player") {
    return {
      ...state,
      player: {
        ...state.player,
        hp: {
          ...state.player.hp,
          current,
        },
      },
    };
  }

  const entity = state.entities[entityId];
  if (entity === undefined || entity.kind !== "enemy") {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [entityId]: {
        ...entity,
        currentHP: current,
      } satisfies EnemyEntityInstance,
    },
  };
};

import { bounds, config } from "../../config/index.js";
import type { EngineLogEventDataByType, GameState } from "../state/index.js";
import {
  registerTickHook,
  type TickHook,
  type TickHooks,
  type TurnEvent
} from "../turn/index.js";

export type PlayerHudPulseField =
  | "level"
  | "xp"
  | "hp"
  | "maxHp"
  | "attack"
  | "defense"
  | "fullness";

export type PlayerHudPulse = {
  readonly pulse: true;
  readonly fields: readonly PlayerHudPulseField[];
};

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly level_up: {
      readonly actorId: "player";
      readonly levelBefore: number;
      readonly levelAfter: number;
      readonly xpBefore: number;
      readonly xpAfter: number;
      readonly xpToNextLevel: number | null;
      readonly maxHpBefore: number;
      readonly maxHpAfter: number;
      readonly currentHpBefore: number;
      readonly currentHpAfter: number;
      readonly hud: PlayerHudPulse;
    };
    readonly starvation: {
      readonly actorId: "player";
      readonly hpBefore: number;
      readonly hpAfter: number;
      readonly fullness: number;
      readonly hud: PlayerHudPulse;
    };
  }
}

export type PlayerBaseStats = {
  readonly maxHp: number;
  readonly attack: number;
  readonly defense: number;
};

export type ApplyXpResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type ApplyNutritionResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

type PlayerLogEventType = "level_up" | "starvation";

type PlayerTickHookName = "hunger" | "regen";

export const xpToNextLevel = (level: number): number =>
  config.playerCharacter.xpToNextLevelFactor * level;

export const derivePlayerBaseStats = (level: number): PlayerBaseStats => {
  const levelOffset = Math.max(
    0,
    level - config.playerCharacter.stats.level.start
  );
  const hpGrowth = config.playerCharacter.stats.hp;
  const attackGrowth = config.playerCharacter.stats.baseAttack;
  const defenseGrowth = config.playerCharacter.stats.baseDefense;

  return {
    maxHp: Math.min(
      bounds.playerCharacter.hpCap,
      hpGrowth.start + levelOffset * hpGrowth.growthPerLevel
    ),
    attack:
      attackGrowth.start +
      Math.floor(levelOffset / attackGrowth.growthEveryLevels) *
        attackGrowth.growthAmount,
    defense:
      defenseGrowth.start +
      Math.floor(levelOffset / defenseGrowth.growthEveryLevels) *
        defenseGrowth.growthAmount
  };
};

export const applyXp = (state: GameState, amount: number): ApplyXpResult => {
  if (!Number.isSafeInteger(amount) || amount <= 0) {
    return applyPendingLevelUps(state);
  }

  return applyPendingLevelUps({
    ...state,
    player: {
      ...state.player,
      xp: state.player.xp + amount
    }
  });
};

export const applyNutrition = (
  state: GameState,
  amount: number
): ApplyNutritionResult => {
  if (!Number.isSafeInteger(amount) || amount === 0) {
    return { state, events: [] };
  }

  const fullnessAfter = clamp(
    state.player.fullness.current + amount,
    0,
    bounds.playerCharacter.overfedFullnessCap
  );
  const maxFullnessAfter = fullnessMaxFor(fullnessAfter);

  if (
    fullnessAfter === state.player.fullness.current &&
    maxFullnessAfter === state.player.fullness.max
  ) {
    return { state, events: [] };
  }

  return {
    state: withPlayerFullness(state, fullnessAfter, maxFullnessAfter),
    events: []
  };
};

const tickHunger: TickHook = ({ state }) => {
  const leveled = applyPendingLevelUps(state);
  const hunger = applyHungerForCompletedTurn(leveled.state);

  return {
    state: hunger.state,
    events: [...leveled.events, ...hunger.events]
  };
};

const tickNaturalRegen: TickHook = ({ state }) => {
  const completedTurn = state.run.turn + 1;
  const regen = config.playerCharacter.naturalRegen;

  if (completedTurn % regen.everyTurns !== 0) {
    return state;
  }

  if (state.player.fullness.current <= regen.requiresFullnessAbove) {
    return state;
  }

  if (state.player.hp.current >= state.player.hp.max) {
    return state;
  }

  const hpBefore = state.player.hp.current;
  const hpAfter = Math.min(state.player.hp.max, hpBefore + regen.hpGain);

  if (hpAfter === hpBefore) {
    return state;
  }

  return {
    state: withPlayerHp(state, hpAfter, state.player.hp.max),
    events: []
  };
};

export const playerTickHooks = {
  hunger: tickHunger,
  regen: tickNaturalRegen
} as const satisfies Pick<TickHooks, PlayerTickHookName>;

export const unregisterPlayerTickHooks = (() => {
  const unregisterHunger = registerTickHook("hunger", tickHunger);
  const unregisterRegen = registerTickHook("regen", tickNaturalRegen);

  return () => {
    unregisterRegen();
    unregisterHunger();
  };
})();

const applyPendingLevelUps = (state: GameState): ApplyXpResult => {
  const events: TurnEvent[] = [];
  let nextState = state;

  while (
    nextState.player.level < bounds.playerCharacter.levelCap &&
    nextState.player.xp >= xpToNextLevel(nextState.player.level)
  ) {
    const levelBefore = nextState.player.level;
    const xpBefore = nextState.player.xp;
    const maxHpBefore = nextState.player.hp.max;
    const currentHpBefore = nextState.player.hp.current;
    const threshold = xpToNextLevel(levelBefore);
    const levelAfter = levelBefore + 1;
    const xpAfter = xpBefore - threshold;
    const maxHpAfter = derivePlayerBaseStats(levelAfter).maxHp;
    const hpDelta = maxHpAfter - maxHpBefore;
    const currentHpAfter = Math.min(
      maxHpAfter,
      currentHpBefore + Math.max(0, hpDelta)
    );

    nextState = {
      ...nextState,
      player: {
        ...nextState.player,
        level: levelAfter,
        xp: xpAfter,
        hp: {
          current: currentHpAfter,
          max: maxHpAfter
        }
      }
    };

    events.push(
      playerEvent(state, "level_up", {
        actorId: "player",
        levelBefore,
        levelAfter,
        xpBefore,
        xpAfter,
        xpToNextLevel:
          levelAfter < bounds.playerCharacter.levelCap
            ? xpToNextLevel(levelAfter)
            : null,
        maxHpBefore,
        maxHpAfter,
        currentHpBefore,
        currentHpAfter,
        hud: hudPulse(["level", "xp", "hp", "maxHp", "attack", "defense"])
      })
    );
  }

  return { state: nextState, events };
};

const applyHungerForCompletedTurn = (state: GameState): ApplyXpResult => {
  const completedTurn = state.run.turn + 1;
  const fullness = state.player.fullness.current;

  if (fullness > 0) {
    return applyFullnessDecayForCompletedTurn(state, completedTurn);
  }

  return applyStarvationForCompletedTurn(state, completedTurn);
};

const applyFullnessDecayForCompletedTurn = (
  state: GameState,
  completedTurn: number
): ApplyXpResult => {
  const decay = config.playerCharacter.stats.fullness.decay;

  if (completedTurn % decay.everyTurns !== 0) {
    const normalizedMax = fullnessMaxFor(state.player.fullness.current);
    if (normalizedMax === state.player.fullness.max) {
      return { state, events: [] };
    }

    return {
      state: withPlayerFullness(
        state,
        state.player.fullness.current,
        normalizedMax
      ),
      events: []
    };
  }

  const fullnessAfter = Math.max(
    0,
    state.player.fullness.current - decay.amount
  );
  const maxFullnessAfter = fullnessMaxFor(fullnessAfter);

  return {
    state: withPlayerFullness(state, fullnessAfter, maxFullnessAfter),
    events: []
  };
};

const applyStarvationForCompletedTurn = (
  state: GameState,
  completedTurn: number
): ApplyXpResult => {
  const starvation = config.playerCharacter.stats.fullness.starvationDamage;

  if (completedTurn % starvation.everyTurns !== 0) {
    return { state, events: [] };
  }

  const hpBefore = state.player.hp.current;
  const hpAfter = Math.max(0, hpBefore - starvation.hpLoss);

  if (hpAfter === hpBefore) {
    return { state, events: [] };
  }

  return {
    state: withPlayerHp(state, hpAfter, state.player.hp.max),
    events: [
      playerEvent(state, "starvation", {
        actorId: "player",
        hpBefore,
        hpAfter,
        fullness: state.player.fullness.current,
        hud: hudPulse(["hp", "fullness"])
      })
    ]
  };
};

const withPlayerHp = (
  state: GameState,
  current: number,
  max: number
): GameState => ({
  ...state,
  player: {
    ...state.player,
    hp: {
      current,
      max
    }
  }
});

