      readonly definitionId: string;
      readonly quantity: number;
      readonly stacked: boolean;
    };
    readonly item_dropped: {
      readonly itemInstanceId: string;
      readonly entityId: EntityId;
      readonly definitionId: string;
      readonly quantity: number;
      readonly position: Position;
    };
    readonly item_equipped: {
      readonly itemInstanceId: string;
      readonly definitionId: string;
      readonly slot: EquipTarget;
      readonly swappedItemInstanceId: string | null;
    };
    readonly item_unequipped: {
      readonly itemInstanceId: string;
      readonly definitionId: string;
      readonly slot: EquipTarget;
      readonly inventorySlot: number;
    };
  }
}

type InventoryLogEventType =
  | "item_picked_up"
  | "item_dropped"
  | "item_equipped"
  | "item_unequipped";

const STACKABLE_CONSUMABLE_KINDS = new Set<ItemCategory>([
  "draught",
  "note",
  "throwable",
  "food",
  "tool",
  "coin",
]);

const FULL_INVENTORY_REASON = "Your pack is full.";

export const isStackableConsumable = (definition: ItemDefinition): boolean =>
  STACKABLE_CONSUMABLE_KINDS.has(definition.kind);

export const stackLimitFor = (definition: ItemDefinition): number =>
  isStackableConsumable(definition)
    ? config.playerCharacter.inventory.identicalConsumableStackLimit
    : 1;

export const inventorySlotCount = (state: GameState): number =>
  state.player.inventory.length;

export const countCarriedItems = (inventory: readonly InventorySlot[]): number => {
  let total = 0;

  for (const slot of inventory) {
    if (slot !== null) {
      total += slot.quantity;
    }
  }

  return total;
};

export const totalItemQuantity = (state: GameState): number => {
  let total = countCarriedItems(state.player.inventory);

  if (state.player.equipment.weapon !== null) {
    total += state.player.equipment.weapon.quantity;
  }

  if (state.player.equipment.armor !== null) {
    total += state.player.equipment.armor.quantity;
  }

  for (const charm of state.player.equipment.charms) {
    if (charm !== null) {
      total += charm.quantity;
    }
  }

  for (const entity of Object.values(state.entities)) {
    if (entity.kind === "item") {
      total += entity.quantity;
    }
  }

  return total;
};

export const findInventorySlotIndex = (
  inventory: readonly InventorySlot[],
  itemInstanceId: string,
): number | null => {
  const index = inventory.findIndex(
    (slot) => slot?.itemInstanceId === itemInstanceId,
  );

  return index === -1 ? null : index;
};

export const findStackSlotIndex = (
  inventory: readonly InventorySlot[],
  definitionId: string,
): number | null => {
  for (let index = 0; index < inventory.length; index += 1) {
    const slot = inventory[index];

    if (slot === null || slot === undefined) {
      continue;
    }

    if (
      slot.definition.id === definitionId &&
      slot.quantity < stackLimitFor(slot.definition)
    ) {
      return index;
    }
  }

  return null;
};

export const findEmptyInventorySlotIndex = (
  inventory: readonly InventorySlot[],
): number | null => {
  const index = inventory.findIndex((slot) => slot === null);

  return index === -1 ? null : index;
};

export const canAddQuantityToInventory = (
  inventory: readonly InventorySlot[],
  definition: ItemDefinition,
  quantity: number,
): boolean => remainingInventoryCapacity(inventory, definition) >= quantity;

const remainingInventoryCapacity = (
  inventory: readonly InventorySlot[],
  definition: ItemDefinition,
): number => {
  if (!isStackableConsumable(definition)) {
    return findEmptyInventorySlotIndex(inventory) === null ? 0 : 1;
  }

  const stackLimit = stackLimitFor(definition);
  let capacity = 0;

  for (const slot of inventory) {
    if (slot === null) {
      capacity += stackLimit;
      continue;
    }

    if (
      slot.definition.id === definition.id &&
      slot.quantity < stackLimit
    ) {
      capacity += stackLimit - slot.quantity;
    }
  }

  return capacity;
};

export const addToInventory = (
  state: GameState,
  stack: PlayerItemStack,
): InventoryOperationResult => {
  if (stack.quantity < 1) {
    return {
      illegal: true,
      reason: "Cannot add an empty item stack.",
    };
  }

  if (!isStackableConsumable(stack.definition) && stack.quantity !== 1) {
    return {
      illegal: true,
      reason: "Equipment and key items cannot be stacked.",
    };
  }

  const inventory = [...state.player.inventory];
  let remaining = stack.quantity;
  let itemInstanceId = stack.itemInstanceId;

  while (remaining > 0) {
    const stackIndex = findStackSlotIndex(inventory, stack.definition.id);

    if (stackIndex !== null) {
      const current = inventory[stackIndex];

      if (current === null || current === undefined) {
        return {
          illegal: true,
          reason: "Inventory stack slot invariant violated.",
        };
      }

      const limit = stackLimitFor(current.definition);
      const room = limit - current.quantity;
      const added = Math.min(room, remaining);
      inventory[stackIndex] = {
        itemInstanceId: current.itemInstanceId,
        definition: current.definition,
        quantity: current.quantity + added,
        identified: current.identified,
      };
      remaining -= added;
      continue;
    }

    const emptyIndex = findEmptyInventorySlotIndex(inventory);

    if (emptyIndex === null) {
      return {
        illegal: true,
        reason: FULL_INVENTORY_REASON,
      };
    }

    const limit = stackLimitFor(stack.definition);
    const added = Math.min(limit, remaining);
    inventory[emptyIndex] = {
      itemInstanceId,
      definition: stack.definition,
      quantity: added,
      identified: stack.identified,
    };
    remaining -= added;
    itemInstanceId = `${stack.itemInstanceId}#split-${emptyIndex}`;
  }

  return {
    state: withInventory(state, inventory),
    events: [],
  };
};

export const removeFromInventory = (
  state: GameState,
  itemInstanceId: string,
  quantity = 1,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const slot = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in slot) {
    return slot;
  }

  if (quantity < 1 || quantity > slot.quantity) {
    return {
      illegal: true,
      reason: `Cannot remove ${quantity} from a stack of ${slot.quantity}.`,
    };
  }

  const inventory = [...state.player.inventory];

  if (quantity === slot.quantity) {
    inventory[slotIndex] = null;
  } else {
    inventory[slotIndex] = {
      itemInstanceId: slot.itemInstanceId,
      definition: slot.definition,
      quantity: slot.quantity - quantity,
      identified: slot.identified,
    };
  }

  return {
    state: withInventory(state, inventory),
    events: [],
  };
};

export const splitInventoryStack = (
  state: GameState,
  itemInstanceId: string,
  quantity: number,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const slot = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in slot) {
    return slot;
  }

  if (quantity < 1 || quantity >= slot.quantity) {
    return {
      illegal: true,
      reason: `Cannot split ${quantity} from a stack of ${slot.quantity}.`,
    };
  }

  const emptyIndex = findEmptyInventorySlotIndex(state.player.inventory);

  if (emptyIndex === null) {
    return {
      illegal: true,
      reason: FULL_INVENTORY_REASON,
    };
  }

  const inventory = [...state.player.inventory];
  inventory[slotIndex] = {
    itemInstanceId: slot.itemInstanceId,
    definition: slot.definition,
    quantity: slot.quantity - quantity,
    identified: slot.identified,
  };
  inventory[emptyIndex] = {
    itemInstanceId: `${slot.itemInstanceId}#split`,
    definition: slot.definition,
    quantity,
    identified: slot.identified,
  };

  return {
    state: withInventory(state, inventory),
    events: [],
  };
};

export const groundItemAt = (
  state: GameState,
  position: Position,
): GroundItemEntityInstance | null => {
  const items = Object.values(state.entities)
    .filter(
      (entity): entity is GroundItemEntityInstance =>
        entity.kind === "item" && samePosition(entity.position, position),
    )
    .sort((a, b) => a.id.localeCompare(b.id));

  return items[0] ?? null;
};

export const resolvePickupAction: ActionResolver<PickupAction> = (
  state,
): ActionResolverResult => {
  const groundItem = groundItemAt(state, state.player.position);

  if (groundItem === null) {
    return {

    return {
      illegal: true,
      reason: "There is nothing here to pick up.",
    };
  }

  const stack: PlayerItemStack = {
    itemInstanceId: groundItem.id,
    definition: groundItem.definition,
    quantity: groundItem.quantity,
    identified: groundItem.identified,
  };

  if (!canAddQuantityToInventory(state.player.inventory, stack.definition, stack.quantity)) {
    return {
      illegal: true,
      reason: FULL_INVENTORY_REASON,
    };
  }

  const added = addToInventory(state, stack);

  if ("illegal" in added) {
    return added;
  }

  const nextEntities = { ...added.state.entities };
  delete nextEntities[groundItem.id];

  const stacked =
    findStackSlotIndex(state.player.inventory, stack.definition.id) !== null;

  return {
    state: {
      ...added.state,
      entities: nextEntities,
    },
    events: [
      inventoryEvent(state, "item_picked_up", {
        itemInstanceId: stack.itemInstanceId,
        entityId: groundItem.id,
        definitionId: stack.definition.id,
        quantity: stack.quantity,
        stacked,
      }),
    ],
  };
};

export const dropItem = (
  state: GameState,
  itemInstanceId: string,
  quantity = 1,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const slot = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in slot) {
    return slot;
  }

  if (quantity < 1 || quantity > slot.quantity) {
    return {
      illegal: true,
      reason: `Cannot drop ${quantity} from a stack of ${slot.quantity}.`,
    };
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return {
      illegal: true,
      reason: "The floor layout is not loaded.",
    };
  }

  const placement = findDropPlacement(state, grid, state.player.position);

  if (placement === null) {
    return {
      illegal: true,
      reason: "There is no room to drop that here.",
    };
  }

  const removed = removeFromInventory(state, itemInstanceId, quantity);

  if ("illegal" in removed) {
    return removed;
  }

  const allocation = allocateEntityId(removed.state.ids.entityCounters, "item");
  const entity: GroundItemEntityInstance = {
    id: allocation.id,
    kind: "item",
    definition: slot.definition,
    position: placement,
    currentHP: null,
    statuses: [],
    behaviorRuntime: {},
    quantity,
    identified: slot.identified,
  };

  return {
    state: {
      ...removed.state,
      ids: {
        ...removed.state.ids,
        entityCounters: allocation.entityCounters,
      },
      entities: {
        ...removed.state.entities,
        [entity.id]: entity,
      },
    },
    events: [
      inventoryEvent(state, "item_dropped", {
        itemInstanceId,
        entityId: entity.id,
        definitionId: slot.definition.id,
        quantity,
        position: placement,
      }),
    ],
  };
};

export const equipItem = (
  state: GameState,
  itemInstanceId: string,
  target?: EquipTarget,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const carried = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in carried) {
    return carried;
  }

  if (carried.quantity !== 1) {
    return {
      illegal: true,
      reason: "Split the stack before equipping that item.",
    };
  }

  const resolvedTarget =
    target ?? defaultEquipTarget(carried.definition, state.player.equipment.charms);

  if (resolvedTarget === null) {
    return {
      illegal: true,
      reason: `${carried.definition.kind} items cannot be equipped.`,
    };
  }

  if (!isValidEquipTarget(resolvedTarget, carried.definition)) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} does not fit that equipment slot.`,
    };
  }

  const inventory = [...state.player.inventory];
  inventory[slotIndex] = null;

  const equipment = {
    weapon: state.player.equipment.weapon,
    armor: state.player.equipment.armor,
    charms: [...state.player.equipment.charms],
  };

  let swappedItem: PlayerItemStack | null = null;

  switch (resolvedTarget.kind) {
    case "weapon":
      swappedItem = equipment.weapon;
      equipment.weapon = carried;
      break;
    case "armor":
      swappedItem = equipment.armor;
      equipment.armor = carried;
      break;
    case "charm": {
      const previousCharm = equipment.charms[resolvedTarget.index];
      swappedItem = previousCharm ?? null;
      equipment.charms[resolvedTarget.index] = carried;
      break;
    }
  }

  inventory[slotIndex] = swappedItem;

  return {
    state: {
      ...state,
      player: {
        ...state.player,
        inventory,
        equipment,
      },
    },
    events: [
      inventoryEvent(state, "item_equipped", {
        itemInstanceId,
        definitionId: carried.definition.id,
        slot: resolvedTarget,
        swappedItemInstanceId: swappedItem?.itemInstanceId ?? null,
      }),
    ],
  };
};

export const unequipItem = (
  state: GameState,
  target: EquipTarget,
): InventoryOperationResult => {
  const emptyIndex = findEmptyInventorySlotIndex(state.player.inventory);

  if (emptyIndex === null) {
    return {
      illegal: true,
      reason: FULL_INVENTORY_REASON,
    };
  }

  const equipment = {
    weapon: state.player.equipment.weapon,
    armor: state.player.equipment.armor,
    charms: [...state.player.equipment.charms],
  };

  let unequipped: PlayerItemStack | null = null;

  switch (target.kind) {
    case "weapon":
      unequipped = equipment.weapon;
      equipment.weapon = null;
      break;
    case "armor":
      unequipped = equipment.armor;
      equipment.armor = null;
      break;
    case "charm":
      unequipped = equipment.charms[target.index] ?? null;
      equipment.charms[target.index] = null;
      break;
  }

  if (unequipped === null) {
    return {
      illegal: true,
      reason: "That equipment slot is empty.",
    };
  }

  const inventory = [...state.player.inventory];
  inventory[emptyIndex] = unequipped;

  return {
    state: {
      ...state,
      player: {
        ...state.player,
        inventory,
        equipment,
      },
    },
    events: [
      inventoryEvent(state, "item_unequipped", {
        itemInstanceId: unequipped.itemInstanceId,
        definitionId: unequipped.definition.id,
        slot: target,
        inventorySlot: emptyIndex,
      }),
    ],
  };
};

export const registerInventoryActionResolver = (): (() => void) =>
  registerActionResolver("pickup", resolvePickupAction);

export const unregisterInventoryActionResolver = registerInventoryActionResolver();

const defaultEquipTarget = (
  definition: ItemDefinition,
  charms: readonly (PlayerItemStack | null)[],
): EquipTarget | null => {
  switch (definition.kind) {
    case "weapon":
      return { kind: "weapon" };
    case "armor":
      return { kind: "armor" };
    case "charm":
      return defaultCharmTarget(charms);
    default:
      return null;
  }
};

const defaultCharmTarget = (
  charms: readonly (PlayerItemStack | null)[],
): EquipTarget => {
  const firstEmpty = charms.findIndex((charm) => charm === null);

  return {
    kind: "charm",
    index: firstEmpty === -1 ? 0 : firstEmpty,
  };
};

const isValidEquipTarget = (
  target: EquipTarget,
  definition: ItemDefinition,
): boolean => {
  switch (target.kind) {
    case "weapon":
      return definition.kind === "weapon";
    case "armor":
      return definition.kind === "armor";
    case "charm":
      return (
        definition.kind === "charm" &&
        target.index >= 0 &&
        target.index < config.playerCharacter.equipmentSlots.charms
      );
  }
};

const findDropPlacement = (
  state: GameState,
  grid: TileGrid,
  origin: Position,
): Position | null => {
  const candidates: Position[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      const position = { x, y };

      if (!inBounds(grid, position) || !isWalkableTile(getTile(grid, position))) {
        continue;
      }

      if (groundItemAt(state, position) !== null) {
        continue;
      }

      candidates.push(position);
    }
  }

  candidates.sort((a, b) => {
    const distanceDelta =
      chebyshevDistance(origin, a) - chebyshevDistance(origin, b);

    if (distanceDelta !== 0) {
      return distanceDelta;
    }

    if (a.y !== b.y) {
      return a.y - b.y;
    }

    return a.x - b.x;
  });

  return candidates[0] ?? null;
};

type InventorySlotReadError = {
  readonly illegal: true;
  readonly reason: string;
};

const readInventorySlot = (
  inventory: readonly InventorySlot[],
  slotIndex: number,
  itemInstanceId: string,
): PlayerItemStack | InventorySlotReadError => {
  const slot = inventory[slotIndex];

  if (slot === null || slot === undefined) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  return slot;
};

const withInventory = (
  state: GameState,
  inventory: readonly InventorySlot[],
): GameState => ({
  ...state,
  player: {
    ...state.player,
    inventory,
  },
});

};

const applyFullnessDecayForCompletedTurn = (
  state: GameState,
  completedTurn: number
): ApplyXpResult => {
  const decay = config.playerCharacter.stats.fullness.decay;

  if (completedTurn % decay.everyTurns !== 0) {
    const normalizedMax = fullnessMaxFor(state.player.fullness.current);
    if (normalizedMax === state.player.fullness.max) {
      return { state, events: [] };
    }

    return {
      state: withPlayerFullness(
        state,
        state.player.fullness.current,
        normalizedMax
      ),
      events: []
    };
  }

  const fullnessAfter = Math.max(
    0,
    state.player.fullness.current - decay.amount
  );
  const maxFullnessAfter = fullnessMaxFor(fullnessAfter);

  return {
    state: withPlayerFullness(state, fullnessAfter, maxFullnessAfter),
    events: []
  };
};

const applyStarvationForCompletedTurn = (
  state: GameState,
  completedTurn: number
): ApplyXpResult => {
  const starvation = config.playerCharacter.stats.fullness.starvationDamage;

  if (completedTurn % starvation.everyTurns !== 0) {
    return { state, events: [] };
  }

  const hpBefore = state.player.hp.current;
  const hpAfter = Math.max(0, hpBefore - starvation.hpLoss);

  if (hpAfter === hpBefore) {
    return { state, events: [] };
  }

  return {
    state: withPlayerHp(state, hpAfter, state.player.hp.max),
    events: [
      playerEvent(state, "starvation", {
        actorId: "player",
        hpBefore,
        hpAfter,
        fullness: state.player.fullness.current,
        hud: hudPulse(["hp", "fullness"])
      })
    ]
  };
};

const withPlayerHp = (
  state: GameState,
  current: number,
  max: number
): GameState => ({
  ...state,
  player: {
    ...state.player,
    hp: {
      current,
      max
    }
  }
});

const withPlayerFullness = (
  state: GameState,
  current: number,
  max: number
): GameState => ({
  ...state,
  player: {
    ...state.player,
    fullness: {
      current,
      max
    }
  }
});

const fullnessMaxFor = (fullness: number): number =>
  fullness > bounds.playerCharacter.fullnessCap
    ? bounds.playerCharacter.overfedFullnessCap
    : bounds.playerCharacter.fullnessCap;

const hudPulse = (fields: readonly PlayerHudPulseField[]): PlayerHudPulse => ({
  pulse: true,
  fields
});

const clamp = (value: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, value));

const playerEvent = <Type extends PlayerLogEventType>(
  state: GameState,
  type: Type,
  data: EngineLogEventDataByType[Type]
): Extract<TurnEvent, { readonly type: Type }> =>
  ({
    turn: state.run.turn,
    type,
    data
  }) as Extract<TurnEvent, { readonly type: Type }>;

const UINT32_SIZE = 0x1_0000_0000;
const UINT32_MAX = UINT32_SIZE - 1;
const FNV_OFFSET_BASIS = 0x811c_9dc5;
const FNV_PRIME = 0x0100_0193;
const STREAM_SEPARATOR = "\u001f";

export interface Rng {
  nextUint32(): number;
  fork(label: string): Rng;
  int(min: number, max: number): number;
  pick<T>(items: readonly T[]): T;
  weightedPick<T>(items: readonly T[], weights: readonly number[]): T;
  shuffle<T>(items: readonly T[]): T[];
  percent(p: number): boolean;
}

export function createRng(seed: string): Rng {
  return new SeededRng(streamKeyForSeed(seed));
}

class SeededRng implements Rng {
  #state: number;

  constructor(private readonly streamKey: string) {
    this.#state = hashStringToUint32(streamKey);
  }

  nextUint32(): number {
    this.#state = (this.#state + 0x6d2b_79f5) >>> 0;

    let value = this.#state;
    value = Math.imul(value ^ (value >>> 15), value | 1);
    value ^= value + Math.imul(value ^ (value >>> 7), value | 61);

    return (value ^ (value >>> 14)) >>> 0;
  }

  fork(label: string): Rng {
    return new SeededRng(streamKeyForFork(this.streamKey, label));
  }

  int(min: number, max: number): number {
    assertSafeInteger(min, "min");
    assertSafeInteger(max, "max");

    if (min > max) {
      throw new RangeError("min must be less than or equal to max");
    }

    const range = max - min + 1;
    if (range < 1 || range > UINT32_SIZE) {
      throw new RangeError("range must contain between 1 and 4294967296 values");
    }

    const limit = UINT32_SIZE - (UINT32_SIZE % range);
    let value = this.nextUint32();

    while (value >= limit) {
      value = this.nextUint32();
    }

    return min + (value % range);
  }

  pick<T>(items: readonly T[]): T {
    assertNonEmpty(items, "items");
    return getAt(items, this.int(0, items.length - 1));
  }

  weightedPick<T>(items: readonly T[], weights: readonly number[]): T {
    assertNonEmpty(items, "items");

    if (items.length !== weights.length) {
      throw new RangeError("items and weights must have the same length");
    }

    let total = 0;
    for (const weight of weights) {
      assertSafeInteger(weight, "weight");

      if (weight < 0) {
        throw new RangeError("weights must be greater than or equal to 0");
      }

      total += weight;
      if (total > UINT32_MAX) {
        throw new RangeError("total weight must be less than or equal to 4294967295");
      }
    }

    if (total === 0) {
      throw new RangeError("at least one weight must be greater than 0");
    }

    const roll = this.int(1, total);
    let runningTotal = 0;

    for (let index = 0; index < weights.length; index += 1) {
      runningTotal += getAt(weights, index);
      if (roll <= runningTotal) {
        return getAt(items, index);
      }
    }

    throw new Error("weighted pick failed to select an item");
  }

  shuffle<T>(items: readonly T[]): T[] {
    const shuffled = [...items];

    for (let index = shuffled.length - 1; index > 0; index -= 1) {
      const swapIndex = this.int(0, index);
      const value = getAt(shuffled, index);
      shuffled[index] = getAt(shuffled, swapIndex);
      shuffled[swapIndex] = value;
    }

    return shuffled;
  }

  percent(p: number): boolean {
    assertSafeInteger(p, "p");

    if (p < 0 || p > 100) {
      throw new RangeError("p must be between 0 and 100");
    }

    return this.int(1, 100) <= p;
  }
}

function hashStringToUint32(value: string): number {
  let hash = FNV_OFFSET_BASIS;

  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, FNV_PRIME) >>> 0;
  }

  return hash >>> 0;
}

function streamKeyForSeed(seed: string): string {
  return `seed${STREAM_SEPARATOR}${seed.length}${STREAM_SEPARATOR}${seed}`;
}

function streamKeyForFork(parentKey: string, label: string): string {
  return [
    "fork",
    parentKey.length.toString(),
    parentKey,
    label.length.toString(),
    label,
  ].join(STREAM_SEPARATOR);
}

function assertSafeInteger(value: number, name: string): void {
  if (!Number.isSafeInteger(value)) {
    throw new RangeError(`${name} must be a safe integer`);
  }
}

function assertNonEmpty<T>(items: readonly T[], name: string): void {
  if (items.length === 0) {
    throw new RangeError(`${name} must not be empty`);
  }
}

function getAt<T>(items: readonly T[], index: number): T {
  if (index < 0 || index >= items.length) {
    throw new RangeError("index out of bounds");
  }

  return items[index] as T;
}

/*
 * PHASE-07B FROZEN TURN EXTENSION INTERFACE
 *
 * A turn always resolves in this order:
 * 1. the player action resolves through built-in handling or the action-resolver
 *    registry;
 * 2. every other actor runs exactly once in stable actor-id order;
 * 3. end-of-turn tick hooks run in this fixed order:
 *    damageOverTime -> durations -> hunger -> regen.
 *
 * Frozen extension surface:
 * - registerActionResolver handles move/attack/use_item/pickup/talk/inspect.
 * - registerTickHook handles damageOverTime/durations/hunger/regen.
 * - TurnHooks.actorTurn handles non-player actors in stable actor-id order.
 * - TurnHooks.ticks handles per-step tick overrides.
 *
 * Do not rename action kinds or TickHookName values, reorder TICK_HOOK_ORDER, or
 * let resolvers/hooks call ambient nondeterminism or LLMs. Resolvers and hooks
 * must return deterministic state/events.
 */

