        .max(bounds.playerCharacter.overfedFullnessCap),
      max: z
        .number()
        .int()
        .positive()
        .max(bounds.playerCharacter.overfedFullnessCap),
    }),
    position: PositionSchema,
    inventory: z
      .array(PlayerItemStackSchema.nullable())
      .length(config.playerCharacter.inventory.slots),
